import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { truncateContent } from '../src/truncateContent';

describe('truncateContent', () => {
  // Happy path: typical string shorter than maxLength
  it('should handle happy path with content shorter than maxLength', () => {
    const result = truncateContent('Hello world', 20);
    expect(result).toBe('Hello world');
  });

  // Edge case: content exactly at maxLength and with multibyte characters
  it('should handle edge case when content length equals maxLength', () => {
    const content = '😀'.repeat(10); // each emoji is 2 UTF-16 code units, length 20
    const maxLength = content.length;
    const result = truncateContent(content, maxLength);
    expect(result).toBe(content);
  });

  // Null/empty handling
  it('should handle null/empty inputs gracefully', () => {
    // @ts-expect-error testing runtime behaviour with null
    expect(truncateContent(null, 10)).toBe('');
    // @ts-expect-error testing runtime behaviour with undefined
    expect(truncateContent(undefined, 10)).toBe('');
    expect(truncateContent('', 10)).toBe('');
    expect(truncateContent('Non‑empty', 0)).toBe('');
  });
});

